// frontend/src/App.js
import { BrowserRouter, Routes, Route, Link, Navigate } from "react-router-dom";
import { AuthProvider, useAuth, hasRole } from "./AuthContext";
import { PrivateRoute, RoleGuard } from "./routeGuards";
import Login from "./components/Login";
import CRMPage from "./pages/CRMPage"; // ← thêm

// ===== Pages mẫu giữ nguyên (Home/Users/Customers/Contracts/Payments/403/404) =====
// ... (nguyên file của bạn) ...

function Home() {
    const { user, logout } = useAuth();
    const isAdmin = hasRole(user, "ADMIN");
    const isSales = hasRole(user, "SALES");
    const isAccountant = hasRole(user, "ACCOUNTANT");

    return (
        <div style={{ padding: 16 }}>
            <h2>Trang chủ</h2>

            {user ? (
                <>
                    <p>Xin chào, <b>{user.username}</b></p>
                    <p>Roles: {user.roles?.join(", ") || "(none)"}</p>
                    <button onClick={logout}>Đăng xuất</button>
                </>
            ) : (
                <p>Bạn chưa đăng nhập</p>
            )}

            <nav style={{ marginTop: 12 }}>
                <Link to="/">Home</Link>
                {isAdmin && <> | <Link to="/users">Users</Link></>}
                {(isAdmin || isSales) && <> | <Link to="/customers">Customers</Link></>}
                {(isAdmin || isSales) && <> | <Link to="/contracts">Contracts</Link></>}
                {(isAdmin || isAccountant) && <> | <Link to="/payments">Payments</Link></>}
                <> | <Link to="/crm">CRM</Link></>
                <> | <Link to="/login">Login</Link></>
            </nav>
        </div>
    );
}

function Users() { /* ... giữ nguyên ... */ return (<div style={{padding:16}}><h3>User Management</h3><p>Chức năng quản trị (chỉ ADMIN).</p></div>); }
function Customers() { return (<div style={{padding:16}}><h3>Customers</h3><p>Trang dành cho ADMIN và SALES.</p></div>); }
function Contracts() { return (<div style={{padding:16}}><h3>Contracts</h3><p>Trang dành cho ADMIN và SALES.</p></div>); }
function Payments() { return (<div style={{padding:16}}><h3>Payments</h3><p>Trang dành cho ADMIN và ACCOUNTANT.</p></div>); }
function Forbidden() { return (<div style={{padding:16}}><h3>403 - Không có quyền truy cập</h3><Link to="/">Về Home</Link></div>); }
function NotFound() { return (<div style={{padding:16}}><h3>404 - Không tìm thấy trang</h3><Link to="/">Về Home</Link></div>); }

// ===== App Root =====
export default function App() {
    return (
        <AuthProvider>
            <BrowserRouter>
                <Routes>
                    {/* Public */}
                    <Route path="/login" element={<Login />} />

                    {/* Protected CRM */}
                    <Route
                        path="/crm"
                        element={
                            <PrivateRoute>
                                <CRMPage />
                            </PrivateRoute>
                        }
                    />

                    {/* Protected khác */}
                    <Route
                        path="/"
                        element={
                            <PrivateRoute>
                                {/* Nếu muốn vào CRM luôn khi vào "/" thì dùng Navigate */}
                                <Navigate to="/crm" replace />
                            </PrivateRoute>
                        }
                    />

                    <Route
                        path="/users"
                        element={
                            <PrivateRoute>
                                <RoleGuard roles={["ADMIN"]}>
                                    <Users />
                                </RoleGuard>
                            </PrivateRoute>
                        }
                    />

                    <Route
                        path="/customers"
                        element={
                            <PrivateRoute>
                                <RoleGuard roles={["ADMIN", "SALES"]}>
                                    <Customers />
                                </RoleGuard>
                            </PrivateRoute>
                        }
                    />

                    <Route
                        path="/contracts"
                        element={
                            <PrivateRoute>
                                <RoleGuard roles={["ADMIN", "SALES"]}>
                                    <Contracts />
                                </RoleGuard>
                            </PrivateRoute>
                        }
                    />

                    <Route
                        path="/payments"
                        element={
                            <PrivateRoute>
                                <RoleGuard roles={["ADMIN", "ACCOUNTANT"]}>
                                    <Payments />
                                </RoleGuard>
                            </PrivateRoute>
                        }
                    />

                    <Route path="/403" element={<Forbidden />} />
                    <Route path="*" element={<NotFound />} />
                </Routes>
            </BrowserRouter>
        </AuthProvider>
    );
}
